pub fn as_agent_loop_spec(&self) -> AgentLoopSpec {
        AgentLoopSpec {
            instruction: self.instruction.clone(),
            tools: self.tools.clone(),
            on_denial: self.on_denial,
            model: self.model.clone(),
            max_iterations: self.max_iterations,
            backend: Backend::Http,
            provider: self.provider,
            wall_clock_timeout_seconds: self.wall_clock_timeout_seconds,
        }
    }

pub fn as_str(self) -> &'static str {
        match self {
            Backend::Http => "http",
            Backend::Cli => "cli",
            Backend::Auto => "auto",
        }
    }

pub fn parse(raw: &str) -> Option<Self> {
        match raw.trim() {
            "http" => Some(Backend::Http),
            "cli" => Some(Backend::Cli),
            "auto" => Some(Backend::Auto),
            _ => None,
        }
    }

pub fn as_str(self) -> &'static str {
        match self {
            Provider::Claude => "claude",
            Provider::Codex => "codex",
            Provider::Gemini => "gemini",
            Provider::Ollama => "ollama",
            Provider::OpenaiCompat => "openai_compat",
        }
    }

pub fn has_http_transport(self) -> bool {
        matches!(self, Provider::Claude)
    }

pub fn item_number(self) -> u32 {
        match self {
            HttpOnlyFeature::CrossIterationSession => 1,
        }
    }

pub fn description(self) -> &'static str {
        match self {
            HttpOnlyFeature::CrossIterationSession => "cross-iteration `session:` binding",
        }
    }

pub fn new() -> Self {
        Self::default()
    }

pub fn load_dir(&mut self, dir: &Path) -> Result<(), CatalogError> {
        self.load_dir_inner(dir, false).map(|_| ())
    }

pub fn load_dir_skipping_retired(&mut self, dir: &Path) -> Result<Vec<PathBuf>, CatalogError> {
        self.load_dir_inner(dir, true)
    }

fn load_dir_inner(
        &mut self,
        dir: &Path,
        skip_retired: bool,
    ) -> Result<Vec<PathBuf>, CatalogError> {
        let mut name_source: BTreeMap<String, PathBuf> = self
            .entries
            .keys()
            .map(|k| (k.clone(), PathBuf::from("<pre-loaded>")))
            .collect();
        let mut skipped = Vec::new();
        walk_dir(dir, &mut |path| {
            let yaml = std::fs::read_to_string(path).map_err(|source| CatalogError::ReadFile {
                path: path.to_path_buf(),
                source,
            })?;
            let asset = match load_activity_asset(&yaml) {
                Ok(asset) => asset,
                Err(source @ AssetLoadError::RetiredVersion(_)) if skip_retired => {
                    skipped.push(path.to_path_buf());
                    return Ok(());
                }
                Err(source) => {
                    return Err(CatalogError::Parse {
                        path: path.to_path_buf(),
                        source,
                    });
                }
            };
            if let Some(prev) = name_source.get(&asset.name) {
                return Err(CatalogError::DuplicateName {
                    name: asset.name,
                    first: prev.clone(),
                    second: path.to_path_buf(),
                });
            }
            name_source.insert(asset.name.clone(), path.to_path_buf());
            self.entries.insert(asset.name, asset.spec);
            Ok(())
        })?;
        Ok(skipped)
    }

pub fn insert(&mut self, name: impl Into<String>, spec: ActivityV2) -> Option<ActivityV2> {
        self.entries.insert(name.into(), spec)
    }

pub fn get(&self, name: &str) -> Option<&ActivityV2> {
        self.entries.get(name)
    }

pub fn len(&self) -> usize {
        self.entries.len()
    }

pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

pub fn names(&self) -> impl Iterator<Item = &str> {
        self.entries.keys().map(String::as_str)
    }

fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            JobKind::Workflow => write!(f, "workflow"),
            JobKind::Subroutine => write!(f, "subroutine"),
        }
    }

fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
        use serde::de::Error as _;
        let mut v = Value::deserialize(deserializer)?;
        let obj = v
            .as_object_mut()
            .ok_or_else(|| D::Error::custom("step must be a mapping"))?;

        let id = obj
            .remove("id")
            .and_then(|x| x.as_str().map(String::from))
            .ok_or_else(|| D::Error::custom("step missing `id`"))?;
        let when = obj
            .remove("when")
            .and_then(|x| x.as_str().map(String::from));
        let retry = match obj.remove("retry") {
            Some(rv) => Some(
                serde_json::from_value::<RetrySpec>(rv)
                    .map_err(|e| D::Error::custom(format!("retry: {e}")))?,
            ),
            None => None,
        };

        let has_parallel = obj.contains_key("parallel");
        let has_fan_out = obj.contains_key("fan_out");
        let has_loop = obj.contains_key("loop");
        let has_target = obj.contains_key("target");

        let body = match (has_parallel, has_fan_out, has_loop) {
            (true, false, false) => {
                let block = obj.remove("parallel").unwrap();
                JobV2StepBody::Parallel {
                    parallel: serde_json::from_value(block)
                        .map_err(|e| D::Error::custom(format!("parallel: {e}")))?,
                }
            }
            (false, true, false) => {
                let fan_out_block = obj.remove("fan_out").unwrap();
                let fan_in_block = obj
                    .remove("fan_in")
                    .ok_or_else(|| D::Error::custom("fan_out step missing matching `fan_in`"))?;
                JobV2StepBody::FanOut {
                    fan_out: serde_json::from_value(fan_out_block)
                        .map_err(|e| D::Error::custom(format!("fan_out: {e}")))?,
                    fan_in: serde_json::from_value(fan_in_block)
                        .map_err(|e| D::Error::custom(format!("fan_in: {e}")))?,
                }
            }
            (false, false, true) => {
                let block = obj.remove("loop").unwrap();
                JobV2StepBody::Loop {
                    loop_: serde_json::from_value(block)
                        .map_err(|e| D::Error::custom(format!("loop: {e}")))?,
                }
            }
            (false, false, false) if has_target => JobV2StepBody::TargetRef(
                serde_json::from_value(Value::Object(std::mem::take(obj)))
                    .map_err(|e| D::Error::custom(format!("target ref: {e}")))?,
            ),
            (false, false, false) => JobV2StepBody::Target(
                serde_json::from_value(Value::Object(std::mem::take(obj)))
                    .map_err(|e| D::Error::custom(format!("target step: {e}")))?,
            ),
            _ => {
                return Err(D::Error::custom(
                    "step may set exactly one of `parallel`, `fan_out`, or `loop`",
                ));
            }
        };

        Ok(JobV2Step {
            id,
            when,
            retry,
            body,
        })
    }

fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
        let v = Value::deserialize(deserializer)?;
        if let Some(s) = v.as_str() {
            return Ok(PipelineRef::Literal(s.to_string()));
        }
        if let Some(obj) = v.as_object()
            && let Some(from) = obj.get("from").and_then(|x| x.as_str())
        {
            return Ok(PipelineRef::Block {
                from: from.to_string(),
            });
        }
        Err(serde::de::Error::custom(
            "PipelineRef must be either a string or a block with `from:`",
        ))
    }

pub fn parse_yaml(yaml: &str) -> Result<Self, serde_yaml::Error> {
        serde_yaml::from_str::<SchemaHeader>(yaml)
    }

pub fn agent(name: impl Into<String>, model: impl Into<String>) -> Self {
        Self::Agent {
            name: name.into().trim().to_string(),
            model: model.into().trim().to_string(),
        }
    }

pub fn human(label: impl Into<String>) -> Self {
        Self::Human {
            label: label.into().trim().to_string(),
        }
    }

pub fn from_legacy(agent: Option<&str>, model: Option<&str>) -> Self {
        match (
            agent.filter(|s| !s.trim().is_empty()),
            model.filter(|s| !s.trim().is_empty()),
        ) {
            (Some(name), Some(model)) => Self::Agent {
                name: name.trim().to_string(),
                model: model.trim().to_string(),
            },
            (Some(name), None) => Self::Agent {
                name: name.trim().to_string(),
                model: String::new(),
            },
            (None, _) => Self::System,
        }
    }

pub fn agent_name(&self) -> Option<&str> {
        match self {
            Self::Agent { name, .. } => Some(name),
            _ => None,
        }
    }

pub fn agent_model(&self) -> Option<&str> {
        match self {
            Self::Agent { model, .. } if !model.is_empty() => Some(model),
            _ => None,
        }
    }

pub fn label(&self) -> String {
        match self {
            Self::System => "system".to_string(),
            Self::Agent { name, model } if model.is_empty() => name.clone(),
            Self::Agent { name, model } => format!("{name} / {model}"),
            Self::Human { label } => label.clone(),
        }
    }

pub fn is_agent(&self) -> bool {
        matches!(self, Self::Agent { .. })
    }

pub fn is_system(&self) -> bool {
        matches!(self, Self::System)
    }

pub fn is_human(&self) -> bool {
        matches!(self, Self::Human { .. })
    }

pub fn to_legacy(&self) -> (Option<String>, Option<String>) {
        match self {
            Self::System => (None, None),
            Self::Agent { name, model } => (
                Some(name.clone()),
                if model.is_empty() {
                    None
                } else {
                    Some(model.clone())
                },
            ),
            Self::Human { .. } => (None, None),
        }
    }

fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.label())
    }

fn serialize<S: Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
        serializer.serialize_str(&self.label())
    }

fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
        use serde::de;

        struct ActorVisitor;

        impl<'de> de::Visitor<'de> for ActorVisitor {
            type Value = ActorIdentity;

            fn expecting(&self, formatter: &mut Formatter) -> std::fmt::Result {
                formatter.write_str(
                    r#""system", or {"agent": {"name": "...", "model": "..."}}, or {"human": "..."}"#,
                )
            }

            fn visit_str<E: de::Error>(self, value: &str) -> Result<ActorIdentity, E> {
                match value {
                    "system" => Ok(ActorIdentity::System),
                    other => {
                        // Legacy: bare string like "claude / opus-4.6" or "human"
                        if other.contains(" / ") {
                            let parts: Vec<&str> = other.splitn(2, " / ").collect();
                            Ok(ActorIdentity::Agent {
                                name: parts[0].trim().to_string(),
                                model: parts[1].trim().to_string(),
                            })
                        } else if other == "human" {
                            Ok(ActorIdentity::Human {
                                label: "human".to_string(),
                            })
                        } else {
                            // Could be an agent name without model, or a human label
                            Ok(ActorIdentity::Human {
                                label: other.to_string(),
                            })
                        }
                    }
                }
            }

            fn visit_map<M: de::MapAccess<'de>>(
                self,
                mut map: M,
            ) -> Result<ActorIdentity, M::Error> {
                let key: String = map
                    .next_key()?
                    .ok_or_else(|| de::Error::custom("expected 'agent' or 'human' key"))?;
                match key.as_str() {
                    "agent" => {
                        let fields: AgentFields = map.next_value()?;
                        Ok(ActorIdentity::Agent {
                            name: fields.name,
                            model: fields.model,
                        })
                    }
                    "human" => {
                        let label: String = map.next_value()?;
                        Ok(ActorIdentity::Human { label })
                    }
                    other => Err(de::Error::unknown_field(other, &["agent", "human"])),
                }
            }
        }

        deserializer.deserialize_any(ActorVisitor)
    }

