pub fn rebuild_pipeline_before(&self, step_index: u32) -> Value {
        let mut pipeline = self.initial_input.clone();
        for (_, patch) in self.pipeline_patches.range(..step_index) {
            merge_pipeline_patch(&mut pipeline, patch);
        }
        pipeline
    }

