pub fn merged(global: &Self, workspace: &Self) -> Result<Self, OrbitError> {
        let mut fs_profiles = global.fs_profiles.clone();
        for (name, profile) in &workspace.fs_profiles {
            fs_profiles.insert(name.clone(), profile.clone());
